import{_ as r,o as i,c as o,ac as l}from"./chunks/framework.DnBnwVZk.js";const p=JSON.parse('{"title":"Dubbo源码-RPC调用","description":"","frontmatter":{"date":"2020-04-02T00:00:00.000Z","categories":["Dubbo"],"tags":["Dubbo","源码"]},"headers":[],"relativePath":"views/java/dubbo/2020/DubboRPC.md","filePath":"views/java/dubbo/2020/DubboRPC.md","lastUpdated":1775803235000}'),t={name:"views/java/dubbo/2020/DubboRPC.md"};function a(n,e,c,v,s,d){return i(),o("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1585785600000"},[...e[0]||(e[0]=[l('<h1 id="dubbo源码-rpc调用" tabindex="-1">Dubbo源码-RPC调用 <a class="header-anchor" href="#dubbo源码-rpc调用" aria-label="Permalink to &quot;Dubbo源码-RPC调用&quot;">​</a></h1><h2 id="_1-provider" tabindex="-1">1. Provider <a class="header-anchor" href="#_1-provider" aria-label="Permalink to &quot;1. Provider&quot;">​</a></h2><p>Dubbo调用中，Provider方提供监听程序，在监听到某个Service的调用后，通过内部的代理来调用对应实例的相应方法，将结果或异常序列化后通过socket连接返回给调用方</p><h3 id="_1-1-init-export" tabindex="-1">1.1 Init &amp; export <a class="header-anchor" href="#_1-1-init-export" aria-label="Permalink to &quot;1.1 Init &amp; export&quot;">​</a></h3><ol><li>Spring扫描<code>BeanDefinition</code>的过程中，Dubbo通过<code>ServiceAnnotationBeanPostProcessor</code>介入，来将带有Dubbo自定义注解<code>@Service</code>的类注册成<code>BeanDefinition</code></li><li>在Bean实例初始化过程中，上述<code>BeanDefinition</code>被初始化成<code>ServiceBean</code>实例，内部存储Service的所有配置信息，包括URL</li><li>Spring发布ContextRefreshed事件后，DubboBootstrap的start方法被触发，在初始化相关环境后，开始exportService</li><li>export:遍历所有的ServiceBean，调用其export方法(实际上是父类ServiceConfig类的实现): <ol><li>初始化serviceMetadata对象</li><li>注册Service到ServiceRepository</li><li>解析HostIp,顺序：环境变量(DUBBO_IP_TO_BIND) -&gt; Java System Properties(DUBBO_IP_TO_BIND) -&gt; 配置文件配置(单独配置或全局配置) -&gt; /etc/hosts -&gt; InetAddress类获取到的第一个可用IP</li><li>解析HostPort,顺序:环境变量(DUBBO_PORT_TO_BIND) -&gt; Java system properties -&gt; 配置文件配置 -&gt; 传输协议默认端口 -&gt; 随机端口</li><li>创建Invoker：ProxyFactory的getInvoker将代理包装成Invoker对象</li><li>调用Wrapper方法，启动qos，进行filter</li><li>Invoker包装成InvokerDelegate</li><li>构建InvokerChain，Invoker包装成匿名内部类</li><li>调用到DubboProtocol的invoke方法</li><li>启动监听服务器:层层包装：NettyServer-&gt;HeaderExchangeServer-&gt;ExchangeServer-&gt;DubboProtocolServer</li><li>优化序列化过程</li><li>向注册中心注册provider url</li><li>发布ServiceDefinition</li></ol></li></ol><h3 id="_1-2-provider-invoker调用" tabindex="-1">1.2 Provider Invoker调用 <a class="header-anchor" href="#_1-2-provider-invoker调用" aria-label="Permalink to &quot;1.2 Provider Invoker调用&quot;">​</a></h3><p>Provider被调用的入口<code>DecodeHandler.received</code>方法，此方法顺序调用<code>ChannelHandler.received</code>-&gt; <code>HeaderExchangeHandler.handleRequest</code> -&gt; <code>DubboProtocol匿名内部类的reply</code>方法，开始调用链：</p><ol><li>Invoker的包装链</li></ol><p>Invoker -&gt; ProxyFactory匿名Wrapper -&gt; AbstractProxyInvoker -&gt; DelegateProviderMetaDataInvoker -&gt; InvokerWrapper -&gt; ProtocolFilterWrapper</p><p>调用与包装链相反，即先调用ProtocolFilterWrapper，顺序调用到实际实现类 2. ProtocolFilterWrapper内部存储了大量Filter实现，调用时会根据注解的Order来顺序调用 - EchoFilter：处理echo协议 - ClassLoaderFilter：更换ClassLoader为Proxy Target的ClassLoader - GenericFilter：处理泛型调用,即<code>$invoke(&quot;xxxMethod&quot;,[paramtypes],[params])</code>类型的调用 - ContextFilter：处理上下文 - TraceFilter：跟踪处理时间等 - TimeoutFilter：处理超时 - MonitorFilter：处理监控数据上报 - ExceptionFilter：异常处理</p><h2 id="_2-consumer" tabindex="-1">2. Consumer <a class="header-anchor" href="#_2-consumer" aria-label="Permalink to &quot;2. Consumer&quot;">​</a></h2><p>参与Consumer的rpc调用的主要插件有：</p><ul><li>ServiceRepository：存储所有的Service,Consumer和Provider</li><li>ConsumerModel：</li><li>RouterFactory：创建Router对象</li><li>Router：负责处理路由策略</li><li>RouterChain: 顾名思义，路由链</li><li>RegistryDirectory：处理注册中心的url转换与存储，注册与订阅逻辑</li><li>MetadataService：存储ServiceDefinition</li><li>Invoker：实际执行调用</li></ul><h3 id="_2-1-init-refer" tabindex="-1">2.1 Init &amp; refer <a class="header-anchor" href="#_2-1-init-refer" aria-label="Permalink to &quot;2.1 Init &amp; refer&quot;">​</a></h3><p>Spring初始化单例Bean过程中，对@Reference注解的Field，初始化并注入一个ReferenceBean。然后创建代理类，连接Transporter和实际执行逻辑的Bean，代理创建流程如下</p><ol><li>初始化、升级Config <ol><li>初始化、从注册中心拉取、校验ConsumerConfig</li><li>读取可能的dubbo resolve 文件：dubbo-resolve.properties</li></ol></li><li>初始化serivceMetadata</li><li>校验Stub实现</li><li>获取ServiceRepository并注册Consumer</li><li>ServiceRepository创建Proxy： <ol><li>判断是否走本地Jvm代理：主要是判断Service的scope属性是否是&quot;local&quot;</li><li>获取并校验注册中心列表</li><li>调用RegistryProtocol.refer方法获取Invoker <ol><li>生成RegistryDirectory</li><li>参数处理，URL处理，构建成Consumer URL，即:consumer://192.168.1.1/some.interface?的形式</li><li>注册Consumer：将上面构建的ConsumerUrl转换成文件路径，调用RegistryDirectory的register方法尝试注册到注册中心，consumer注册完成</li><li>构建RouterChain：调用所有的RouterFactory来获取Router列表并排序</li><li>订阅Provider：调用RegistryDirectory的subscribe方法，获取下列路径的文件 <ul><li>/dubbo/name.of.service/providers</li><li>/dubbo/name.of.service/configurators</li><li>/dubbo/name.of.service/routers</li></ul></li><li>根据获取到的Provider的URL列表，构建InvokerChain，Invoker的构造过程见[Invoker构造](### 2.3),构建InvokerChain即获取所有的Filter并链式调用Invoker</li><li>上面构建成InvokerChain后的Invoker包装成InvokerDelegate</li><li>cluster.join后，上面的Invoker再包装成MockClusterInvoker</li></ol></li><li>检测Invoker是否连接，如果Service的所有Invoker都无法连接，报错退出</li><li>PublishServiceDefinition:把对应接口的ServiceDefinition放到MetadataService里</li><li>使用ProxyFactory把Invoker对象代理成对应接口，底层实现为JavaassistProxyFactory，Dubbo在JDK自带Proxy的基础上进行了代码的二次编译</li></ol></li><li>发布事件:ReferenceConfigInitializedEvent</li></ol><h3 id="_2-2-referencebean的主要属性" tabindex="-1">2.2 ReferenceBean的主要属性 <a class="header-anchor" href="#_2-2-referencebean的主要属性" aria-label="Permalink to &quot;2.2 ReferenceBean的主要属性&quot;">​</a></h3><ol><li>ServiceMetadata:Service的元信息：接口名，Group，version等信息</li><li>ConsumerConfig:保存Consumer配置信息，包括代理相关的策略name，调度相关的线程池参数，RPC相关的客户端类型等</li><li>ServiceDescriptor：Service描述符，跟ServiceMeta属性重复，这部分有很多冗余代码</li><li>RegistryConfig:注册中心配置</li><li>MetadataService：存储与发布Service元数据</li><li>RegistryDirectory：存储到注册中心的文件夹</li></ol><h3 id="_2-3-invoker构造过程" tabindex="-1">2.3 Invoker构造过程 <a class="header-anchor" href="#_2-3-invoker构造过程" aria-label="Permalink to &quot;2.3 Invoker构造过程&quot;">​</a></h3><ol><li>根据URL,获取ExchangeClient数组</li><li>初始化Exchanger，默认使用HeaderExchanger，ExchangeHandler使用Dubbo内部类</li><li>初始化DubboClient，设置代理目标Interface,url,ExchangeClient数组,invoker数组</li><li>构造-&gt;DubboInvoker组件构成 <ol><li>列表-DubboClient： <ol><li>url</li><li>interface</li><li>ExchangeClient <ol><li>ExchangeChannel</li><li>Handler</li></ol></li><li>Invokers</li></ol></li><li>version</li><li>invokers-&gt;指向Protocol的Invoker列表</li></ol></li><li>层层包装:DubboInvoker-&gt;AsyncToSyncInvoker-&gt;ListenerInvokerWrapper</li></ol><p>附：Invoker千层饼层层包装：</p><p>DubboInvoker -&gt; AsysncToSyncInvoker -&gt; ListenerInvokerWrapper -&gt; ProtocolFilterWrapper -&gt; InvokerDelegate -&gt; AbstractClusterInvoker -&gt; AbstractCluster.InterceptorInvokerNode -&gt; MockClusterInvoker</p><h3 id="_2-4-invoker调用过程" tabindex="-1">2.4 Invoker调用过程 <a class="header-anchor" href="#_2-4-invoker调用过程" aria-label="Permalink to &quot;2.4 Invoker调用过程&quot;">​</a></h3><p>逆向沿Invoker对应的包装过程一路调用下去</p><ol><li>MockClusterInvoker:创建RpcInvocation对象，判断是否Mock，非Mock继续调用</li><li>AbstractCluster.InterceptorInvokerNode: <ol><li>before:创建RpcContext</li><li>调用内部的Invoker</li><li>after:清理RpcContext</li></ol></li><li>AbstractClusterInvoker: <ol><li>顺序调用Router获取Invoker列表</li><li>初始化LoadBalance:未指定的话是Random</li><li>获取默认重试次数</li><li>带重试，选取并调用使用的Invoker <ol><li>有sticky Invoker直接返回它</li><li>调用策略选取一个Invoker，但是在下面的情况下会触发reselect <ol><li>本次调用在重试，且前面已经调用过这个Invoker，表明这个Invoker很可能有问题</li><li>选取的Invoker不可用</li></ol></li><li>调用Invoker</li></ol></li></ol></li><li>ProtocolFilterWrapper:</li><li>AsyncToSyncInvoker: <ol><li>上下文属性处理</li><li>调用DubboInvoker的Invoke方法</li><li>阻塞直到拿到result或抛出异常</li></ol></li><li>DubboInvoker:调用ExchangeClient的send(不需要获取响应的情况)或者request方法(需要获取响应的情况)，返回CompletableFuture给上层 <ol><li>底层调用HeaderExchangeChannel的send/request方法</li><li>返回Future对象</li></ol></li></ol><p>总结：Router-&gt;LoadBalance-&gt;reTry-&gt;Invoke</p>',26)])])}const b=r(t,[["render",a]]);export{p as __pageData,b as default};
